import React, { useState, useEffect } from 'react';
import SpecialistAreas from '../components/SpecialistAreas';

const Home = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const banners = [
    '/images/Banner/1.jpg',
    '/images/Banner/2.jpg',
    '/images/Banner/3.jpg'
  ];

  const clients = [
    { src: '/images/Clients/Clients1.png', alt: 'KHANSAHEB', width: '252px' },
    { src: '/images/Clients/Clients2.png', alt: 'AL Basti & Muktha LLC', width: '373px' },
    { src: '/images/Clients/Clients3.png', alt: 'ThyssenKrupp', width: '278px' },
    { src: '/images/Clients/Clients4.png', alt: 'MEGARME', width: '310px' },
    { src: '/images/Clients/Clients5.png', alt: 'New Trade Links LLC', width: '359px' },
    { src: '/images/Clients/Clients6.png', alt: 'Ferrotech International Fze', width: '310px' },
    { src: '/images/Clients/Clients7.png', alt: 'Al Ghandi Electronics', width: '359px' },
    { src: '/images/Clients/Clients8.png', alt: 'Hi-Tec', width: '221px' },
    { src: '/images/Clients/Clients9.png', alt: 'Somec-Sharaf', width: '221px' },
    { src: '/images/Clients/Clients10.png', alt: 'STADLERS', width: '221px' },
    { src: '/images/Clients/Clients11.png', alt: 'AL REYAMI', width: '221px' },
    { src: '/images/Clients/Clients12.png', alt: 'Dutco Balfour Beatty LLC', width: '221px' },
    { src: '/images/Clients/Clients13.png', alt: 'AL REYAMI INTERIORS', width: '221px' }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % banners.length);
    }, 5000);
    return () => clearInterval(interval);
  }, [banners.length]);

  return (
    <div className="pageContainer">
      {/* Banner Slider */}
      <div className="SliderShowView">
        <div className="slideshow">
          <ul className="buttons">
            {banners.map((_, index) => (
              <li key={index} id={`btnNav0${index + 1}`} className={index === currentSlide ? 'active' : ''}>
                <a title={index + 1} href="#">.</a>
              </li>
            ))}
          </ul>
          <ul className="slides">
            {banners.map((src, index) => (
              <li 
                key={index} 
                id={`imgSlider0${index + 1}`} 
                className={`slide ${index === currentSlide ? 'active' : ''}`}
              >
                <img src={src} alt="Sun Emirates" title="Sun Emirates" />
              </li>
            ))}
          </ul>
        </div>
      </div>

      {/* Main Content */}
      <table cellpadding="2" cellspacing="0" border="0" width="100%">
        <tbody>
          <tr>
            <td style={{ width: '70%' }}>
              <div className="ContentsView innerLeftPane">
                <p className="pspan">The Company</p>
                <p className="parp">
                  We are pleased to introduce ourselves as <b>SUN EMIRATES MECHANICAL WORKS LLC</b>,
                  expertise in Steel structural designers and contractors and one of the growing steel
                  fabrication company located in Al Shenaya New Industrial area , Ajman, U.A.E established
                  in 2007. We have been in the business of stainless steel and mild steel fabrication
                  for Construction, Interior Decoration, Marine, Power and Oil & Gas sectors.
                </p>
                <p className="parp">
                  We have experienced technical team who expertise on producing ranges of products
                  in time with best quality to meet with the requirement and specification of the
                  clients.
                </p>
              </div>
            </td>
            <td style={{ width: '30%', overflow: 'auto' }} className="osa">
              <div className="innerRightPane osa">
                <SpecialistAreas />
              </div>
            </td>
          </tr>
          <tr>
            <td align="left" colSpan={2}>
              <p className="pspan">Our Clients</p>
            </td>
          </tr>
          <tr>
            <td align="left" colSpan={2} className="clientplan">
              <div className="image_carousel">
                <div>
                  {clients.map((client, index) => (
                    <img 
                      key={index}
                      src={client.src} 
                      alt={client.alt} 
                      width={client.width} 
                      height="152px" 
                      align="absMiddle"
                      title={client.alt}
                    />
                  ))}
                </div>
                <div className="clearfix"></div>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  );
};

export default Home;
